INSERT INTO gym_action (id, name, alias, pinyin_bref, action_type, movement_pattern, difficulty_level, image_urls, action_guide, safety_tips, search_keywords, is_common, status) VALUES
('ACT1001', '上斜杠铃卧推', 'Incline Barbell Bench Press', 'sxglwt', 'COMPOUND', 'PUSH', 2, '[]', '上斜凳调至30°~45°，双手略宽于肩握杠铃，下放至锁骨位置，呼气推起。', '角度切勿过高，否则三角肌前束借力过多。下放时控制速度。', '["上胸","杠铃","复合动作"]', 1, 1),
('ACT1002', '上斜哑铃卧推', 'Incline Dumbbell Press', 'sxylwt', 'COMPOUND', 'PUSH', 2, '[]', '上斜凳30°~45°，双手持哑铃，从小胸上部垂直向上推起，哑铃自由轨迹更深拉伸。', '哑铃自由度更高，强调下放时胸肌充分拉伸。核心收紧。', '["上胸","哑铃","复合动作"]', 1, 1),
('ACT1003', '上斜哑铃飞鸟', 'Incline Dumbbell Fly', 'sxylfn', 'ISOLATION', 'PUSH', 2, '[]', '上斜凳仰卧，双手持哑铃微屈肘，像抱大树般向两侧打开，胸部发力夹回。', '手肘角度固定不变，用胸部而非手臂发力。轻重量找准发力感。', '["上胸","孤立动作","飞鸟"]', 1, 1),
('ACT1004', '史密斯上斜卧推', 'Smith Incline Press', 'smssxwt', 'COMPOUND', 'PUSH', 1, '[]', '上斜凳置于史密斯架下，双手握杠，从上胸位置向上推起，固定轨迹更安全。', '固定轨迹较安全，适合上胸稳定冲击大重量。手腕不要后翻。', '["上胸","史密斯","固定器械"]', 1, 1),
('ACT1005', '绳索低位上拉夹胸', 'Low Cable Crossover', 'ssdwsljx', 'ISOLATION', 'PUSH', 2, '[]', '龙门架低位滑轮，双手抓握把手，由下向上拉至胸前交叉，顶峰收缩停顿1秒。', '核心收紧，身体不前倾借力，感受上胸挤压。', '["上胸","龙门架","夹胸"]', 1, 1),
('ACT1006', '悍马机上斜推胸', 'Hammer Strength Incline Press', 'hmjsxtx', 'COMPOUND', 'PUSH', 1, '[]', '坐于悍马机，调好座椅高度，双手握把，上胸发力推起，单侧独立发力。', '悍马机单侧发力，弥补上胸不对称。轨迹固定安全。', '["上胸","悍马机","固定器械"]', 1, 1),
('ACT1007', '平板杠铃卧推', 'Barbell Bench Press', 'pbglwt', 'COMPOUND', 'PUSH', 2, '[]', '仰卧平板凳上，双手略宽于肩握杠铃，下放至乳头触及，呼气推起。', '切勿弓背，手腕保持中立，下放控制速度。建议有人保护。', '["胸肌","杠铃","三大项","复合动作"]', 1, 1),
('ACT1008', '平板哑铃卧推', 'Dumbbell Bench Press', 'pbylwt', 'COMPOUND', 'PUSH', 2, '[]', '双手持哑铃仰卧平板凳，由胸外侧垂直向上推起，顶点哑铃不相撞。', '下放时手肘不要过度外展，核心收紧。注意下放时对胸中束的撕裂感。', '["胸肌","哑铃","复合动作"]', 1, 1),
('ACT1009', '坐姿推胸机推胸', 'Chest Press Machine', 'zztxjtx', 'ISOLATION', 'PUSH', 1, '[]', '调好座椅高度，双手握把，背部贴紧靠背，前推至手臂伸直。', '不要耸肩，始终保持胸部张力。适合新手或力竭后补刀。', '["胸肌","固定器械","新手"]', 1, 1),
('ACT1010', '蝴蝶机夹胸', 'Pec Deck Fly', 'hdjjx', 'ISOLATION', 'PUSH', 1, '[]', '坐于蝴蝶机，双臂微屈搭在挡板上，胸部发力将挡板向中间夹拢。', '双臂保持微屈不锁死，充分挤压胸中缝。不要用手臂拉。', '["胸肌","孤立动作","蝴蝶机"]', 1, 1),
('ACT1011', '绳索中位水平夹胸', 'Cable Crossover', 'sszwspjx', 'ISOLATION', 'PUSH', 2, '[]', '龙门架中位滑轮，身体微前倾，双手由两侧向胸前交叉夹拢，顶峰停顿。', '绳索中位交叉夹胸，顶峰停顿挤压。核心稳定不晃动。', '["胸肌","龙门架","夹胸"]', 1, 1),
('ACT1012', '平板哑铃飞鸟', 'Flat Dumbbell Fly', 'pbylfn', 'ISOLATION', 'PUSH', 2, '[]', '仰卧平板凳，双手持哑铃微屈肘，向两侧打开至胸肌充分拉伸，再夹回。', '哑铃下放时手肘微屈，胸肌充分拉伸。重量不宜过大。', '["胸肌","孤立动作","飞鸟"]', 1, 1),
('ACT1013', '双杠臂屈伸（胸肌版）', 'Chest Dip', 'sgbqsxj', 'COMPOUND', 'PUSH', 3, '[]', '双手撑双杠，身体微前倾约30°，屈肘下放至大臂平行双杠，再撑起。', '身体微前倾偏向练胸下缘；身体垂直偏三头。控制下放速度。', '["下胸","自重训练","复合动作"]', 1, 1),
('ACT1014', '下斜杠铃卧推', 'Decline Barbell Bench Press', 'xxglwt', 'COMPOUND', 'PUSH', 2, '[]', '下斜凳调至15°~20°，双手握杠铃，从胸下缘位置向上推起，感受胸下缘发力。', '下斜角度不宜过大。大重量时建议有人保护。', '["下胸","杠铃","复合动作"]', 1, 1),
('ACT1015', '下斜哑铃卧推', 'Decline Dumbbell Press', 'xxylwt', 'COMPOUND', 'PUSH', 2, '[]', '下斜凳仰卧，双手持哑铃，从胸下缘向上推起，自由轨迹刺激下胸轮廓。', '哑铃自由轨迹刺激下胸轮廓。核心收紧保持稳定。', '["下胸","哑铃","复合动作"]', 1, 1),
('ACT1016', '绳索高位下压夹胸', 'High Cable Crossover', 'ssgwxyjx', 'ISOLATION', 'PUSH', 2, '[]', '龙门架高位滑轮，双手握把手由上向下夹压，意念集中在胸下缘。', '身体微前倾，顶峰停顿感受胸下缘挤压。', '["下胸","龙门架","夹胸"]', 1, 1),
('ACT1017', '悍马机下斜推胸', 'Hammer Strength Decline Press', 'hmjxxxtx', 'COMPOUND', 'PUSH', 1, '[]', '坐于悍马机下斜位，双手握把，胸下缘发力推起，单侧独立发力。', '悍马机固定轨迹，安全冲击下胸。弥补下胸不对称。', '["下胸","悍马机","固定器械"]', 1, 1);
INSERT INTO gym_action (id, name, alias, pinyin_bref, action_type, movement_pattern, difficulty_level, image_urls, action_guide, safety_tips, search_keywords, is_common, status) VALUES
('ACT2001', '正手高位下拉', 'Wide Grip Lat Pulldown', 'zsgwxl', 'COMPOUND', 'PULL', 1, '[]', '双手宽握横杠，大腿固定，背阔肌发力将横杠拉至上胸，拉到最低点时停顿1秒。', '严禁耸肩或身体过度后仰借力。控制回放速度。', '["背阔肌","固定器械","倒三角"]', 1, 1),
('ACT2002', '宽握引体向上', 'Wide Grip Pull Up', 'kwytxs', 'COMPOUND', 'PULL', 3, '[]', '双手宽握单杠悬垂，背阔肌发力带动身体向上，至下巴过杠，控制下放。', '下放时控制速度，不要完全死悬垂放松。做不到6次可用弹力带辅助。', '["背阔肌","自重训练","黄金动作"]', 1, 1),
('ACT2003', '反握窄握高位下拉', 'Reverse Grip Lat Pulldown', 'fwzwgwxl', 'COMPOUND', 'PULL', 1, '[]', '反手窄握横杠，双腿固定，背阔肌发力将横杠拉至上胸，更刺激背阔肌下部。', '反握窄握更刺激背阔肌下部。拉到最低点时顶峰收缩。', '["背阔肌","固定器械"]', 1, 1),
('ACT2004', '直臂下压', 'Straight Arm Pulldown', 'zbxy', 'ISOLATION', 'PULL', 2, '[]', '面对龙门架站姿微俯身，双手直臂（微屈）抓把手，背阔肌发力将横杠从高位压至大腿。', '双臂保持微屈不锁死，感受背阔肌拉伸。用背阔肌发力而非手臂。', '["背阔肌","孤立动作","龙门架"]', 1, 1),
('ACT2005', '单臂哑铃划船', 'One-Arm Dumbbell Row', 'dbyldc', 'COMPOUND', 'PULL', 2, '[]', '单手扶凳，另一手持哑铃，肘部贴紧躯干向后上方拉，感受背阔肌收缩。', '核心收紧保持稳定，肘部贴近躯干，不要旋转躯干。', '["背阔肌","哑铃","复合动作"]', 1, 1),
('ACT2006', '悍马机单臂下拉', 'Hammer Strength Unilateral Pulldown', 'hmjdbxl', 'COMPOUND', 'PULL', 1, '[]', '坐于悍马机，单手握把，背阔肌发力向下拉，单侧独立发力纠正背部不对称。', '悍马机单侧下拉，弥补背部不对称。固定轨迹安全。', '["背阔肌","悍马机","固定器械"]', 1, 1),
('ACT2007', '俯身杠铃划船', 'Barbell Bent Over Row', 'fsglhc', 'COMPOUND', 'PULL', 3, '[]', '俯身约45°，双膝微屈，双手略宽于肩，将杠铃拉向肚脐，背部发力集中。', '俯身稳定，严禁借助腰部力量猛甩。全程挺胸塌腰防伤腰。', '["斜方肌","杠铃","复合动作","黄金动作"]', 1, 1),
('ACT2008', '坐姿绳索划船', 'Seated Cable Row', 'zzsshc', 'COMPOUND', 'PULL', 1, '[]', '双脚踩实，双手抓把手，挺胸核心收紧，将把手拉向小腹，背部中间挤压。', '双肩下沉，吐气回拉，专注于背部中间拉紧与松开的控制。', '["斜方肌","龙门架","固定器械"]', 1, 1),
('ACT2009', 'T杠划船', 'T-Bar Row', 'tghc', 'COMPOUND', 'PULL', 2, '[]', '双脚跨立T杠两侧，俯身双手抓握把，背部发力将杠铃拉向胸口。', '胸靠垫减少腰部压力，背部集中发力。', '["斜方肌","杠铃","复合动作"]', 1, 1),
('ACT2011', '蝴蝶机反向飞鸟', 'Reverse Pec Deck', 'hdjfxfn', 'ISOLATION', 'PULL', 1, '[]', '面向蝴蝶机而坐，双手反握挡板，向后打开，专注后束与斜方肌中下部发力。', '蝴蝶机反向飞鸟，专注后束/斜方肌中下部。肩胛骨主动收缩。', '["斜方肌","孤立动作","蝴蝶机"]', 1, 1),
('ACT2012', '哑铃耸肩', 'Dumbbell Shrug', 'ylsj', 'ISOLATION', 'PULL', 1, '[]', '站姿双手持哑铃垂于体侧，斜方肌发力将肩膀向上耸起到最高点，停顿后控制下放。', '大重量短行程，顶点停顿。不要旋转肩膀。', '["斜方肌","孤立动作","哑铃"]', 1, 1),
('ACT2013', '传统硬拉', 'Conventional Deadlift', 'ctyl', 'COMPOUND', 'HINGE', 3, '[]', '双脚与髋同宽站立，杠铃贴小腿，挺胸塌腰，髋膝联动拉起杠铃至身体直立。', '腰部挺直，杠铃贴小腿上下，切勿弓背。佩戴腰带和助力带。', '["竖脊肌","杠铃","三大项","黄金动作"]', 1, 1),
('ACT2014', '罗马尼亚硬拉', 'Romanian Deadlift', 'lmnyyl', 'COMPOUND', 'HINGE', 2, '[]', '双手持杠铃，膝盖微屈，髋部后移，杠铃贴腿下放至小腿中段，专注腘绳肌和竖脊肌拉伸。', '杠铃不过膝，膝盖微屈不锁死。专注腘绳肌和竖脊肌的拉伸。', '["竖脊肌","杠铃","复合动作"]', 1, 1),
('ACT2015', '山羊挺身', 'Hyperextension', 'syts', 'ISOLATION', 'HINGE', 1, '[]', '卡在罗马椅（45度挺身架）上，身体俯身屈曲，下背部和臀部发力将上身抬起至一条直线。', '抬起时身体呈一条直线，切勿过伸导致腰椎超伸。', '["竖脊肌","孤立动作","罗马椅"]', 1, 1);
INSERT INTO gym_action (id, name, alias, pinyin_bref, action_type, movement_pattern, difficulty_level, image_urls, action_guide, safety_tips, search_keywords, is_common, status) VALUES
('ACT3001', '杠铃高位深蹲', 'Barbell Back Squat', 'glgwsd', 'COMPOUND', 'SQUAT', 3, '[]', '杠铃架于斜方肌，脚尖微外展，臀部后坐屈膝下蹲至大腿平行地面，蹬地站起。', '绝对不能弓背，膝盖方向与脚尖一致，切勿内扣。建议佩戴护腰带。', '["股四头肌","杠铃","三大项","王牌动作"]', 1, 1),
('ACT3002', '倒蹬机推举', 'Leg Press', 'ddjtj', 'COMPOUND', 'SQUAT', 1, '[]', '斜躺在倒蹬机上，双脚踩踏板与肩同宽，解锁后屈膝下放再蹬起。', '膝盖切勿完全锁死，臀部不要离开靠垫拱起。踏板高位偏臀，低位偏股四。', '["股四头肌","固定器械","安全练腿"]', 1, 1),
('ACT3003', '坐姿腿屈伸', 'Leg Extension', 'zztqs', 'ISOLATION', 'SQUAT', 1, '[]', '坐姿双手抓紧把手，双脚勾住挡板，股四头肌发力踢起至双腿伸直，顶端短暂停顿。', '动作顶端短暂停顿，充分挤压大腿前侧。控制下放速度。', '["股四头肌","固定器械","孤立动作"]', 1, 1),
('ACT3004', '哈克深蹲', 'Hack Squat', 'hksd', 'COMPOUND', 'SQUAT', 2, '[]', '背靠哈克深蹲机斜板，双脚踩踏板与肩同宽，屈膝下蹲再蹬起，固定轨迹更安全。', '固定轨迹更安全，股四头肌集中发力。膝盖方向同脚尖一致。', '["股四头肌","固定器械","复合动作"]', 1, 1),
('ACT3005', '哑铃向后箭步蹲', 'Dumbbell Reverse Lunge', 'ylxhjbd', 'COMPOUND', 'LUNGE', 2, '[]', '双手持哑铃垂于体侧，一条腿向后迈出一步下蹲，双膝均呈90°，前腿发力蹬回原位。', '核心收紧保持平衡，前脚踩实，后脚脚尖着地。左右交替进行。', '["股四头肌","哑铃","复合动作"]', 1, 1),
('ACT3006', '俯卧腿弯举', 'Lying Leg Curl', 'fwtwj', 'ISOLATION', 'HINGE', 1, '[]', '俯卧于腿弯举机，双脚踝后侧顶住挡板，屈膝将挡板拉向臀部，顶峰停顿。', '骨盆不要大幅抬起借力。顶峰停顿感受腘绳肌收缩。', '["腘绳肌","固定器械","孤立动作"]', 1, 1),
('ACT3007', '坐姿腿弯举', 'Seated Leg Curl', 'zztwj', 'ISOLATION', 'HINGE', 1, '[]', '坐于腿弯举机，脚踝勾紧挡板，腘绳肌发力屈膝下压，控制下放速度。', '脚踝勾紧，控制下放速度。顶峰停顿感受腘绳肌发力。', '["腘绳肌","固定器械","孤立动作"]', 1, 1),
('ACT3008', '直腿硬拉', 'Stiff Leg Deadlift', 'ztyl', 'COMPOUND', 'HINGE', 2, '[]', '双手持杠铃，膝盖微屈不锁死，髋部后移，杠铃贴腿下放，感受腘绳肌拉伸。', '膝盖微屈不锁死，杠铃贴腿。核心收紧保护腰椎。', '["腘绳肌","杠铃","复合动作"]', 1, 1),
('ACT3009', '杠铃臀推', 'Barbell Hip Thrust', 'gltt', 'COMPOUND', 'HINGE', 2, '[]', '上背靠在板凳缘，杠铃置于髋部，双脚踩地，臀部发力将髋部顶起至身体平行。', '动作顶端夹紧臀部，核心收紧挺髋。不要用腰椎顶。建议使用臀推垫。', '["臀大肌","杠铃","翘臀神技"]', 1, 1),
('ACT3010', '史密斯臀推', 'Smith Hip Thrust', 'smstt', 'COMPOUND', 'HINGE', 1, '[]', '上背靠凳，史密斯杠铃置于髋部，固定轨迹向上顶髋，安全冲击臀大肌。', '史密斯固定轨迹，安全冲击臀大肌。顶端夹紧臀部。', '["臀大肌","史密斯","固定器械"]', 1, 1),
('ACT3011', '绳索后踢腿', 'Cable Kickback', 'sshtt', 'ISOLATION', 'HINGE', 1, '[]', '龙门架低位滑轮，脚踝绑带固定，手扶支撑物，臀大肌发力将腿向后上方踢出。', '慢速控制，感受臀部发力。核心收紧保持平衡。', '["臀大肌","龙门架","孤立动作"]', 1, 1),
('ACT3012', '保加利亚单腿蹲', 'Bulgarian Split Squat', 'bjlydtd', 'COMPOUND', 'LUNGE', 2, '[]', '后脚搭在凳子上，前脚踩实，双手持哑铃，屈前膝下蹲至大腿平行地面，再蹬起。', '前脚踩实，后脚搭凳。核心收紧保持平衡，膝盖不超过脚尖。', '["臀大肌","哑铃","复合动作"]', 1, 1),
('ACT3013', '坐姿器械外展', 'Seated Hip Abduction', 'zzqxwz', 'ISOLATION', 'HINGE', 1, '[]', '坐于夹腿机（外展模式），双腿靠挡板外侧，臀中肌发力将双腿向外展打开。', '身体前倾30°更刺激臀中肌。控制回放速度。', '["臀中肌","固定器械","孤立动作"]', 1, 1),
('ACT3014', '站姿杠铃提踵', 'Barbell Standing Calf Raise', 'zzgltz', 'ISOLATION', 'SQUAT', 1, '[]', '站姿杠铃架于斜方肌，双脚前掌踩在台阶边缘，小腿发力踮起脚尖至最高点，控制下放。', '大重量高次数，全程快放慢收。膝盖微屈不锁死。', '["小腿","杠铃","孤立动作"]', 1, 1),
('ACT3015', '坐姿器械提踵', 'Seated Calf Raise', 'zzqxtz', 'ISOLATION', 'SQUAT', 1, '[]', '坐于提踵机，双脚前掌踩踏板，膝盖上方放挡板，小腿发力踮起脚尖再控制下放。', '固定轨迹安全刺激小腿三头肌。大重量高次数。', '["小腿","固定器械","孤立动作"]', 1, 1);
INSERT INTO gym_action (id, name, alias, pinyin_bref, action_type, movement_pattern, difficulty_level, image_urls, action_guide, safety_tips, search_keywords, is_common, status) VALUES
('ACT4001', '坐姿哑铃推举', 'Seated Dumbbell Shoulder Press', 'zzyldj', 'COMPOUND', 'PUSH', 2, '[]', '坐姿挺胸，双手持哑铃于肩外侧，垂直向上推举至手臂伸直，核心收紧手肘不锁死。', '核心收紧，腰部不要过度拱起贴椅背。推起时手肘不锁死。', '["三角肌前束","哑铃","复合动作"]', 1, 1),
('ACT4002', '杠铃推举', 'Barbell Overhead Press', 'gltj', 'COMPOUND', 'PUSH', 3, '[]', '站姿双手略宽于肩握杠铃于锁骨前，核心收紧，垂直向上推举至头顶上方。', '立姿核心收紧，避免腰椎过伸。大重量建议佩戴护腰带。', '["三角肌前束","杠铃","复合动作"]', 1, 1),
('ACT4003', '史密斯坐姿推举', 'Smith Shoulder Press', 'smszztj', 'COMPOUND', 'PUSH', 1, '[]', '调整板凳至史密斯架下，双手握杠，从上胸/下巴位置向上推起，专注前束发力。', '固定轨迹较安全，专注前束发力。手腕不要后翻。', '["三角肌前束","史密斯","固定器械"]', 1, 1),
('ACT4004', '哑铃前平举', 'Dumbbell Front Raise', 'ylqpj', 'ISOLATION', 'PUSH', 1, '[]', '站姿双手持哑铃垂于身前，手臂微屈，前束发力将哑铃抬至肩高即可，不要借力摆动。', '哑铃抬至肩高即可，不要借力摆动。控制下放速度。', '["三角肌前束","哑铃","孤立动作"]', 1, 1),
('ACT4005', '绳索前平举', 'Cable Front Raise', 'ssqpj', 'ISOLATION', 'PUSH', 1, '[]', '背对龙门架低位滑轮，双手抓握绳索把手，前束发力将绳索向前抬起至肩高。', '绳索恒定张力，前束全程受力。身体不晃动借力。', '["三角肌前束","龙门架","孤立动作"]', 1, 1),
('ACT4006', '哑铃侧平举', 'Dumbbell Lateral Raise', 'ylcpj', 'ISOLATION', 'PUSH', 1, '[]', '站姿双手持哑铃垂于身前，双臂微屈向两侧抬起至大臂平行地面，手腕微旋倒水姿势。', '小重量高次数，不要用斜方肌怂肩。手肘稍微高过手腕。', '["三角肌中束","哑铃","孤立动作","南瓜肩"]', 1, 1),
('ACT4007', '绳索单臂侧平举', 'Cable Lateral Raise', 'ssdbcpj', 'ISOLATION', 'PUSH', 1, '[]', '龙门架低位滑轮，单手握绳索把手，手臂微屈向侧上方抬起，恒定张力刺激中束。', '恒定张力刺激中束。身体不晃动，专注中束发力。', '["三角肌中束","龙门架","孤立动作"]', 1, 1),
('ACT4008', '杠铃直立划船', 'Barbell Upright Row', 'glzlhc', 'COMPOUND', 'PULL', 2, '[]', '站姿双手窄握杠铃垂于身前，沿身体前侧向上拉起至下巴高度，肘尖向外打开。', '宽握减少肩关节压力。杠铃贴近身体前侧上行。', '["三角肌中束","杠铃","复合动作"]', 1, 1),
('ACT4009', '器械侧平举', 'Machine Lateral Raise', 'qxcpj', 'ISOLATION', 'PUSH', 1, '[]', '坐于侧平举专用机，双臂外侧靠挡板，中束发力将手臂向外侧抬起至水平。', '固定轨迹，安全高效刺激中束。控制回放速度。', '["三角肌中束","固定器械","孤立动作"]', 1, 1),
('ACT4010', '哑铃俯身侧平举', 'Dumbbell Bent Over Lateral Raise', 'ylfscpj', 'ISOLATION', 'PULL', 2, '[]', '俯身接近平行地面，双膝微屈，双手持哑铃向两侧后方张开，专注后束发力。', '沉肩，用肩后侧发力，不要耸斜方肌。控制晃动。', '["三角肌后束","哑铃","孤立动作"]', 1, 1),
('ACT4011', '蝴蝶机反向飞鸟（肩）', 'Reverse Pec Deck (Rear Delt)', 'hdjfxfnj', 'ISOLATION', 'PULL', 1, '[]', '面向蝴蝶机而坐，双手反握挡板，后束发力将挡板向后打开至肩胛骨收缩。', '专注后束孤立发力。肩胛骨主动后缩。', '["三角肌后束","蝴蝶机","孤立动作"]', 1, 1),
('ACT4012', '绳索面拉', 'Cable Face Pull', 'ssml', 'ISOLATION', 'PULL', 1, '[]', '龙门架高位滑轮，双手握双头绳索，拉向额头，同时外旋手腕，加强肩袖健康。', '拉向额头，外旋手腕加强肩袖健康。身体稳定不晃动。', '["三角肌后束","龙门架","孤立动作","肩袖健康"]', 1, 1),
('ACT4013', '上斜俯卧哑铃反向飞鸟', 'Incline Prone Reverse Fly', 'sxfwylfxfn', 'ISOLATION', 'PULL', 2, '[]', '俯卧于上斜凳（30°~45°），双手持哑铃向两侧后方展开，完全孤立三角肌后束。', '完全孤立三角肌后束。控制下放速度，轻重量高次数。', '["三角肌后束","哑铃","孤立动作"]', 1, 1);
INSERT INTO gym_action (id, name, alias, pinyin_bref, action_type, movement_pattern, difficulty_level, image_urls, action_guide, safety_tips, search_keywords, is_common, status) VALUES
('ACT5001', 'EZ杆曲柄杠铃弯举', 'EZ Bar Curl', 'ezgqbglwj', 'ISOLATION', 'PULL', 1, '[]', '站姿双手握EZ曲柄杠铃，大臂贴紧躯干，肘关节屈曲弯举至顶端挤压二头肌。', '大臂贴紧躯干，身体不晃，顶端挤压。手腕中立舒适位。', '["肱二头肌","EZ杆","孤立动作"]', 1, 1),
('ACT5002', '哑铃交替弯举', 'Alternating Dumbbell Curl', 'yljtwj', 'ISOLATION', 'PULL', 1, '[]', '站姿或坐姿，双手持哑铃垂于体侧，左右手交替向上弯举并外旋手腕，深度刺激二头肌。', '下放时充分拉伸二头肌，控制节奏。上举时微微外旋手腕。', '["肱二头肌","哑铃","孤立动作"]', 1, 1),
('ACT5003', '哑铃锤式弯举', 'Hammer Curl', 'ylhswj', 'ISOLATION', 'PULL', 1, '[]', '站姿双手持哑铃，掌心相对（锤式握法），大臂稳定向上弯举，强化肱肌和前臂。', '掌心相对，强化肱肌和前臂。大臂贴紧躯干不晃动。', '["肱二头肌","哑铃","孤立动作","前臂"]', 1, 1),
('ACT5004', '牧师凳弯举', 'Preacher Curl', 'msdwj', 'ISOLATION', 'PULL', 1, '[]', '坐姿上臂靠在牧师凳斜板上，双手握EZ杆或哑铃，严格孤立二头肌向上弯举。', '严格孤立二头肌，充分拉伸下放。身体不晃动借力。', '["肱二头肌","牧师凳","孤立动作"]', 1, 1),
('ACT5005', '绳索低位弯举', 'Cable Curl', 'ssdwwj', 'ISOLATION', 'PULL', 1, '[]', '面对龙门架低位滑轮，双手握绳索把手，大臂夹紧，二头肌发力向上弯举。', '绳索恒定张力，二头肌全程受力。大臂不移动。', '["肱二头肌","龙门架","孤立动作"]', 1, 1),
('ACT5006', '上斜哑铃弯举', 'Incline Dumbbell Curl', 'sxylwj', 'ISOLATION', 'PULL', 1, '[]', '仰卧于上斜凳（45°），双手持哑铃垂于身后，二头肌发力向上弯举，长头充分拉伸。', '手臂后置，二头肌长头充分拉伸。控制下放感受拉伸。', '["肱二头肌","哑铃","孤立动作"]', 1, 1),
('ACT5007', '绳索下压', 'Cable Triceps Pushdown', 'ssxy', 'ISOLATION', 'PUSH', 1, '[]', '面对龙门架高位滑轮，双手抓绳索或直杆把手，大臂夹紧锁定，三头肌发力向下伸直手臂。', '大臂夹紧锁定不移动，手臂完全伸直收缩。肘关节固定。', '["肱三头肌","龙门架","孤立动作"]', 1, 1),
('ACT5008', '窄握杠铃卧推', 'Close Grip Bench Press', 'zwglwt', 'COMPOUND', 'PUSH', 2, '[]', '仰卧平板凳，双手与肩同宽窄握杠铃，下放至下胸处，三头肌发力推起。', '握距与肩同宽，专注三头肌发力。建议有人保护。', '["肱三头肌","杠铃","复合动作"]', 1, 1),
('ACT5009', '仰卧杠铃臂屈伸', 'Skull Crusher', 'ywglbqs', 'ISOLATION', 'PUSH', 2, '[]', '仰卧平板凳，双手窄握杠铃或EZ杆，肘部指向天花板，屈肘下放杠铃至额头，三头肌发力伸直。', '肘部指向天花板不动，控制下放重量。重量不宜过大。', '["肱三头肌","杠铃","孤立动作"]', 1, 1),
('ACT5010', '哑铃颈后臂屈伸', 'Overhead Dumbbell Extension', 'yljhbqs', 'ISOLATION', 'PUSH', 1, '[]', '坐姿或站姿，单手或双手持哑铃举过头顶，屈肘下放至颈后，三头肌发力伸直手臂。', '上臂贴近耳朵保持不动，仅前臂屈伸。核心收紧。', '["肱三头肌","哑铃","孤立动作"]', 1, 1),
('ACT5011', '双杠臂屈伸（三头版）', 'Triceps Dip', 'sgbqsst', 'COMPOUND', 'PUSH', 3, '[]', '双手撑双杠，身体保持直立垂直，屈肘下放至大臂平行双杠，三头肌发力撑起。', '身体直立垂直偏向三头肌发力。控制下放速度。', '["肱三头肌","自重训练","复合动作"]', 1, 1),
('ACT5012', '绳索颈后过顶臂屈伸', 'Cable Overhead Extension', 'ssjhgdbqs', 'ISOLATION', 'PUSH', 1, '[]', '背对龙门架高位滑轮，双手抓绳索把手举过头顶，屈肘下放再伸直，三头肌长头深度刺激。', '上臂贴近耳朵，恒定张力刺激三头肌长头。核心收紧。', '["肱三头肌","龙门架","孤立动作"]', 1, 1),
('ACT5013', '杠铃正反握腕弯举', 'Barbell Wrist Curl', 'glzfwwnj', 'ISOLATION', 'PULL', 1, '[]', '坐姿前臂垫于大腿上，双手握杠铃手腕悬空，仅手腕屈伸，正反握交替训练前臂。', '仅手腕屈伸，前臂保持稳定。正握练伸腕肌，反握练屈腕肌。', '["前臂","杠铃","孤立动作"]', 1, 1);
INSERT INTO gym_action (id, name, alias, pinyin_bref, action_type, movement_pattern, difficulty_level, image_urls, action_guide, safety_tips, search_keywords, is_common, status) VALUES
('ACT6001', '基础卷腹', 'Crunch', 'jcjf', 'ISOLATION', 'CORE', 1, '[]', '仰卧瑜伽垫，双膝屈曲，双手轻放头侧或胸前，腹直肌发力将上背部抬离地面卷起。', '腰部贴地，用腹肌发力卷起而非脖子。下巴不要贴胸口。', '["腹直肌","自重训练","马甲线"]', 1, 1),
('ACT6002', '仰卧抬腿', 'Leg Raise', 'ywtt', 'ISOLATION', 'CORE', 1, '[]', '仰卧瑜伽垫，双腿并拢微屈，腹直肌发力将双腿抬起至垂直地面，控制下放。', '下放时脚不着地，下腹持续紧张。腰部贴地不拱起。', '["腹直肌","自重训练","下腹"]', 1, 1),
('ACT6003', '悬垂举腿', 'Hanging Leg Raise', 'xcjt', 'ISOLATION', 'CORE', 3, '[]', '双手悬挂单杠，核心发力将双腿（或屈膝）抬高至平行地面以上，用腹部控制下放。', '尽量减少身体前后晃动，用腹部控制下放。高级核心动作。', '["腹直肌","自重训练","下腹","高级核心"]', 1, 1),
('ACT6004', '绳索跪姿卷腹', 'Cable Kneeling Crunch', 'ssgzjf', 'ISOLATION', 'CORE', 2, '[]', '面对龙门架高位滑轮，跪姿双手抓绳索置于颈后，腹肌发力向下蜷缩，顶峰收缩。', '绳索置于颈后，腹肌顶峰收缩。不要用腰部下压。', '["腹直肌","龙门架","孤立动作"]', 1, 1),
('ACT6005', '健腹轮卷腹', 'Ab Wheel Rollout', 'jfljf', 'ISOLATION', 'CORE', 2, '[]', '跪姿双手握健腹轮，向前推行至身体平行地面，腹肌发力拉回，慢放快收。', '慢放快收，核心收紧保护腰椎。力量不足可做半程或靠墙。', '["腹直肌","健腹轮","孤立动作"]', 1, 1),
('ACT6006', '俄罗斯转体', 'Russian Twist', 'elszt', 'ISOLATION', 'CORE', 1, '[]', '坐姿双脚离地，身体后仰保持V字形，双手持药球或哑铃，左右转体交替。', '双脚离地增加难度，控制旋转幅度。不要用惯性甩动。', '["腹斜肌","药球","孤立动作"]', 1, 1),
('ACT6007', '负重侧屈', 'Weighted Side Bend', 'fzcq', 'ISOLATION', 'CORE', 1, '[]', '站姿单手持哑铃，另一手放头侧，身体向负重侧侧屈，对侧腹斜肌拉伸收缩。', '手持哑铃慢慢向下，对侧腹斜肌拉伸。不要前后晃动。', '["腹斜肌","哑铃","孤立动作"]', 1, 1),
('ACT6008', '绳索伐木式转体', 'Cable Woodchop', 'ssfmszt', 'ISOLATION', 'CORE', 2, '[]', '龙门架高位滑轮，双手抓握绳索把手，模拟伐木动作斜向下拉转体，核心旋转发力。', '核心旋转发力，模拟伐木动作。身体稳定不晃动。', '["腹斜肌","龙门架","孤立动作"]', 1, 1),
('ACT6009', '平板支撑', 'Plank', 'pbzc', 'ISOLATION', 'CORE', 1, '[]', '双肘和脚尖支撑瑜伽垫，身体保持一条直线，核心、臀部、大腿紧绷，静态保持。', '切勿塌腰、低头或抬高臀部。身体一条直线。', '["核心深层肌群","自重训练","静力核心"]', 1, 1),
('ACT6010', '健腹轮推行', 'Ab Wheel Rollout (Full)', 'jfltx', 'ISOLATION', 'CORE', 3, '[]', '站姿或跪姿双手握健腹轮，向前推至身体完全伸展，接近地面，核心发力拉回。', '高级核心动作，力量不足可做半程。核心收紧保护腰椎。', '["核心深层肌群","健腹轮","高级核心"]', 1, 1);
INSERT INTO gym_action (id, name, alias, pinyin_bref, action_type, movement_pattern, difficulty_level, image_urls, action_guide, safety_tips, search_keywords, is_common, status) VALUES
('ACT7001', '跑步机慢跑', 'Treadmill Run', 'pbjmp', 'CARDIO', 'CARDIO', 1, '[]', '系好安全扣，开机调整速度，抬头挺胸，规律呼吸，全脚掌着地慢跑。', '切勿玩手机，根据自身心率适度调整速度。心率保持在60%~70%最大心率。', '["有氧","跑步机","减脂","燃脂"]', 1, 1),
('ACT7002', '椭圆机太空漫步', 'Elliptical Workout', 'tyjtkmb', 'CARDIO', 'CARDIO', 1, '[]', '双脚踩实踏板，双手抓活动把手，顺畅交替踩动，膝盖不冲击。', '脚后跟不要抬起，核心收紧。大体重减脂首选不伤膝盖。', '["有氧","椭圆机","减脂","不伤膝盖"]', 1, 1),
('ACT7003', '划船机有氧', 'Rowing Machine Workout', 'hcjyy', 'CARDIO', 'CARDIO', 2, '[]', '双脚固定，蹬腿、展髋、拉手柄至上腹，随后平滑还原。可用HIIT模式交替。', '用腿部和核心发力，保持动作流畅性。全力划行+慢速恢复交替。', '["有氧","划船机","全身燃脂","HIIT"]', 1, 1),
('ACT7004', '动感单车间歇骑行', 'Spinning Bike', 'dgdcjxqx', 'CARDIO', 'CARDIO', 1, '[]', '调好坐垫高度，双脚套入踏板，跟进节奏起立或坐姿骑行，阻力适中。', '控制阻力旋钮，不要完全无阻力空踩伤膝盖。跟音乐节奏骑行。', '["有氧","动感单车","高强度有氧","暴汗"]', 1, 1),
('ACT7005', '壶铃摇摆（有氧）', 'Kettlebell Swing', 'hlybyy', 'CARDIO', 'HINGE', 2, '[]', '双脚宽站立持壶铃，靠髋部屈伸爆发力将壶铃向前荡起至胸口高度，持续高心率。', '用屁股和大腿后侧"荡"起来，而不是用手臂拉。髋铰链发力。', '["有氧","壶铃","爆发力","燃脂"]', 1, 1),
('ACT7006', 'TRX胸部拉伸', 'TRX Chest Stretch', 'trxxbls', 'STRETCH', 'CORE', 1, '[]', '双手抓TRX带子背向锚点，身体前倾，双臂向两侧张开感受胸部拉伸，静态保持。', '核心保持稳定，不要塌腰。每个静态姿势保持30~60秒。', '["拉伸","TRX","放松","胸部"]', 1, 1),
('ACT7007', '泡沫轴背部滚揉', 'Foam Roller Back Rolling', 'pmzbbgr', 'MOBILITY', 'CORE', 1, '[]', '泡沫轴垫于上背部，双脚踩地抬高臀部，上下滚动按摩背部肌群，针对酸痛点缓慢滑行。', '注意不要滚揉没有肋骨保护的下腰部。每个部位1~2分钟。', '["筋膜放松","泡沫轴","恢复"]', 1, 1);
